"use client";
import React from 'react';
import { useJournal } from '../context/JournalContext';
import { Target, ListTodo, Star } from 'lucide-react';

const Semana: React.FC = () => {
  const { state, updateWeek } = useJournal();
  const { week } = state;

  const handleImportantChange = (index: number, value: string) => {
    const newList = [...week.importantThings];
    newList[index] = value;
    updateWeek({ importantThings: newList });
  };

  return (
    <div className="space-y-6 max-w-2xl mx-auto">
      <header className="border-b border-rose-pastel pb-4">
        <h2 className="text-3xl font-serif text-soft-text font-light italic">Esta Semana</h2>
        <p className="text-soft-text/60 font-medium">Enfoque y metas</p>
      </header>

      {/* Meta de la semana */}
      <section className="bg-white p-8 rounded-3xl journal-shadow border border-rose-pastel/30 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <Target size={80} className="text-deep-rose" />
        </div>
        <div className="flex items-center gap-2 mb-4 text-deep-rose font-medium">
          <Target size={20} />
          <h3>Meta Principal</h3>
        </div>
        <textarea
          value={week.goal}
          onChange={(e) => updateWeek({ goal: e.target.value })}
          placeholder="¿Cuál es tu gran objetivo para estos días?"
          className="w-full h-20 bg-transparent border-none outline-none resize-none text-xl text-soft-text placeholder:italic font-serif"
        />
      </section>

      {/* Cosas importantes */}
      <section className="bg-white p-6 rounded-3xl journal-shadow border border-rose-pastel/30">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-medium">
          <ListTodo size={20} />
          <h3>Cosas Importantes</h3>
        </div>
        <div className="space-y-4">
          {week.importantThings.map((item, i) => (
            <div key={i} className="flex items-center gap-4 bg-lavender-pastel/20 p-3 rounded-2xl border border-lavender-pastel/50">
              <span className="w-8 h-8 flex items-center justify-center bg-white rounded-full text-accent-lavender font-bold shadow-sm">
                {i + 1}
              </span>
              <input
                type="text"
                value={item}
                onChange={(e) => handleImportantChange(i, e.target.value)}
                placeholder="Escribe algo relevante..."
                className="flex-1 bg-transparent border-none outline-none text-soft-text"
              />
            </div>
          ))}
        </div>
      </section>

      {/* Algo que espero con emoción */}
      <section className="bg-accent-lavender/20 p-8 rounded-3xl border border-accent-lavender/30">
        <div className="flex items-center gap-2 mb-4 text-deep-rose font-medium">
          <Star size={20} className="fill-accent-pink text-accent-pink" />
          <h3>Algo que espero con emoción</h3>
        </div>
        <input
          type="text"
          value={week.excitedAbout}
          onChange={(e) => updateWeek({ excitedAbout: e.target.value })}
          placeholder="Un evento, una cita, un momento..."
          className="w-full bg-transparent border-b border-white focus:border-deep-rose outline-none py-2 text-lg text-soft-text italic"
        />
      </section>
    </div>
  );
};

export default Semana;
