"use client";

import React, { useState, useEffect, useRef } from 'react';
import { Calendar, Home, BookOpen, Star, FileText } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import FloralDecoration from './FloralDecoration';
import Scene3D from './Scene3D';
import gsap from 'gsap';

const TABS = [
  { id: 'hoy', name: 'Hoy', icon: Home },
  { id: 'semana', name: 'Semana', icon: Calendar },
  { id: 'habitos', name: 'Hábitos', icon: Star },
  { id: 'devocional', name: 'Devocional', icon: BookOpen },
  { id: 'notas', name: 'Notas', icon: FileText },
];

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (id: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const sidebarRef = useRef<HTMLDivElement>(null);
  const mainRef = useRef<HTMLElement>(null);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    // Animación de entrada suave - solo si ya están visibles
    if (sidebarRef.current && mainRef.current) {
      gsap.from(sidebarRef.current, { x: -50, opacity: 0.5, duration: 1, ease: "power3.out" });
      gsap.from(mainRef.current, { y: 20, opacity: 0.5, duration: 0.8, ease: "power3.out" });
    }
  }, []);

  if (!mounted) return null;

  return (
    <div className="flex min-h-screen bg-cream-pastel overflow-hidden relative selection:bg-accent-pink/40 text-soft-text">
      {/* Capas de fondo con opacidad muy baja para no interferir */}
      <div className="opacity-10"><Scene3D /></div>
      <div className="opacity-10"><FloralDecoration /></div>
      
      {/* Sidebar - Desktop */}
      <aside 
        ref={sidebarRef}
        className="hidden md:flex flex-col w-64 bg-white/60 backdrop-blur-xl border-r border-rose-pastel shadow-lg z-10"
      >
        <div className="p-8">
          <h1 className="text-3xl font-serif text-deep-rose italic font-bold leading-tight">
            Diario de <br/> Abigail
          </h1>
          <div className="w-12 h-1 bg-accent-pink mt-4 rounded-full opacity-50" />
          <p className="text-[10px] uppercase tracking-widest font-bold text-soft-text mt-6 opacity-40">v1.0.0 — ✨</p>
        </div>
        
        <nav className="flex-1 px-4 py-6 space-y-3">
          {TABS.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`w-full flex items-center space-x-4 px-5 py-4 rounded-2xl transition-all duration-300 group ${
                activeTab === tab.id 
                  ? 'bg-white text-deep-rose font-bold shadow-md translate-x-1' 
                  : 'text-soft-text/70 hover:bg-white/40 hover:text-soft-text'
              }`}
            >
              <tab.icon size={20} strokeWidth={2.5} className={activeTab === tab.id ? 'text-accent-pink' : 'group-hover:text-accent-pink transition-colors'} />
              <span className="text-sm font-bold tracking-tight">{tab.name}</span>
            </button>
          ))}
        </nav>

        <div className="p-8 mt-auto italic text-[11px] font-medium text-soft-text/40 leading-relaxed">
          "Cada día es una nueva oportunidad para crecer."
        </div>
      </aside>

      {/* Main Content */}
      <main 
        ref={mainRef}
        className="flex-1 flex flex-col min-h-screen relative overflow-y-auto pb-24 md:pb-0 z-10"
      >
        <header className="md:hidden p-5 bg-white/90 backdrop-blur-md border-b border-rose-pastel flex justify-between items-center sticky top-0 z-20">
          <h1 className="text-xl font-serif text-deep-rose italic font-bold">Diario de Abigail</h1>
          <div className="w-10 h-10 rounded-full bg-rose-pastel flex items-center justify-center">
            <Star className="text-accent-pink fill-accent-pink" size={20} />
          </div>
        </header>

        <div className="flex-1 p-5 md:p-12 max-w-4xl mx-auto w-full">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, scale: 0.99 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 1.01 }}
              transition={{ duration: 0.3 }}
            >
              {children}
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Bottom Navigation - Mobile */}
        <nav className="md:hidden fixed bottom-6 left-5 right-5 bg-white/95 backdrop-blur-lg border border-rose-pastel rounded-[2rem] flex justify-around p-3 shadow-2xl z-30 ring-4 ring-rose-pastel/10">
          {TABS.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex flex-col items-center p-3 rounded-2xl transition-all ${
                activeTab === tab.id ? 'text-deep-rose bg-rose-pastel' : 'text-soft-text/50'
              }`}
            >
              <tab.icon size={22} strokeWidth={activeTab === tab.id ? 2.5 : 2} />
              {activeTab === tab.id && <span className="text-[10px] mt-1 font-bold">{tab.name}</span>}
            </button>
          ))}
        </nav>
      </main>
    </div>
  );
};

export default Layout;
