import React from 'react';

const FloralDecoration: React.FC = () => {
  return (
    <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden opacity-20">
      {/* Esquina superior derecha */}
      <svg className="absolute -top-10 -right-10 w-64 h-64 text-accent-pink" viewBox="0 0 200 200">
        <path fill="currentColor" d="M40,100 Q40,40 100,40 T160,100 T100,160 T40,100" />
        <circle cx="100" cy="100" r="10" fill="white" />
      </svg>
      
      {/* Esquina inferior izquierda */}
      <svg className="absolute -bottom-20 -left-20 w-80 h-80 text-accent-lavender rotate-45" viewBox="0 0 200 200">
        <path fill="currentColor" d="M40,100 Q40,40 100,40 T160,100 T100,160 T40,100" />
        <circle cx="100" cy="100" r="10" fill="white" />
      </svg>

      {/* Pequeños pétalos dispersos */}
      <div className="absolute top-1/4 left-1/4 w-4 h-4 rounded-full bg-accent-pink/30 blur-sm animate-pulse" />
      <div className="absolute bottom-1/3 right-1/4 w-3 h-3 rounded-full bg-accent-lavender/30 blur-sm animate-bounce" style={{ animationDuration: '4s' }} />
    </div>
  );
};

export default FloralDecoration;
