"use client";
import React, { useState } from 'react';
import { useJournal } from '../context/JournalContext';
import { Sparkles, Plus, Check } from 'lucide-react';

const DAYS = ['L', 'M', 'M', 'J', 'V', 'S', 'D'];

const Habitos: React.FC = () => {
  const { state, toggleHabitDay, addHabit } = useJournal();
  const [newHabitName, setNewHabitName] = useState('');

  const handleAddHabit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newHabitName.trim()) {
      addHabit(newHabitName);
      setNewHabitName('');
    }
  };

  return (
    <div className="space-y-6 max-w-4xl mx-auto">
      <header className="border-b border-rose-pastel pb-4">
        <h2 className="text-3xl font-serif text-soft-text font-light italic">Seguimiento de Hábitos</h2>
        <p className="text-soft-text/60 font-medium">Consistencia y crecimiento personal</p>
      </header>

      <div className="bg-white rounded-3xl journal-shadow border border-rose-pastel/30 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-rose-pastel/20">
                <th className="p-4 md:p-6 font-medium text-deep-rose">Hábito</th>
                {DAYS.map((day, i) => (
                  <th key={i} className="p-4 md:p-6 text-center text-soft-text/60 text-sm">{day}</th>
                ))}
                <th className="p-4 md:p-6 text-center text-deep-rose font-medium">Total</th>
              </tr>
            </thead>
            <tbody>
              {state.habits.map((habit) => {
                const completedCount = habit.completedDays.filter(Boolean).length;
                return (
                  <tr key={habit.id} className="border-t border-rose-pastel/20 hover:bg-lavender-pastel/5 transition-colors">
                    <td className="p-4 md:p-6 font-medium text-soft-text">{habit.name}</td>
                    {habit.completedDays.map((completed, dayIdx) => (
                      <td key={dayIdx} className="p-2 md:p-4 text-center">
                        <button
                          onClick={() => toggleHabitDay(habit.id, dayIdx)}
                          className={`w-8 h-8 md:w-10 md:h-10 rounded-full transition-all flex items-center justify-center border-2 
                            ${completed 
                              ? 'bg-accent-pink border-accent-pink text-white scale-110' 
                              : 'border-rose-pastel/40 hover:border-accent-pink'}`}
                        >
                          {completed && <Check size={18} />}
                        </button>
                      </td>
                    ))}
                    <td className="p-4 md:p-6 text-center">
                      <span className="bg-lavender-pastel text-deep-rose px-3 py-1 rounded-full text-sm font-bold">
                        {completedCount}/7
                      </span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      <form onSubmit={handleAddHabit} className="flex gap-3 bg-white p-4 rounded-2xl journal-shadow border border-rose-pastel/30 max-w-md">
        <input
          type="text"
          value={newHabitName}
          onChange={(e) => setNewHabitName(e.target.value)}
          placeholder="Nuevo hábito..."
          className="flex-1 bg-transparent border-none outline-none text-soft-text px-2"
        />
        <button 
          type="submit"
          className="bg-accent-pink text-white p-2 rounded-xl hover:bg-deep-rose/40 transition-colors flex items-center gap-2 px-4"
        >
          <Plus size={20} />
          <span className="hidden sm:inline">Agregar</span>
        </button>
      </form>

      <div className="bg-rose-pastel/30 p-6 rounded-3xl border border-rose-pastel/60 flex items-center gap-4">
        <Sparkles className="text-deep-rose shrink-0" size={32} />
        <p className="text-soft-text text-sm italic">
          "Pequeños hábitos diarios resultan en grandes cambios a largo plazo. ¡Sigue así, Abigail!"
        </p>
      </div>
    </div>
  );
};

export default Habitos;
