"use client";
import React, { useState } from 'react';
import { useJournal } from '../context/JournalContext';
import { CheckCircle2, Circle, Plus, Heart, Sparkles, NotepadText, Lightbulb } from 'lucide-react';
import { motion } from 'framer-motion';

const MOODS = [
  { emoji: '😊', label: 'Feliz' },
  { emoji: '🌸', label: 'Tranquila' },
  { emoji: '✨', label: 'Inspirada' },
  { emoji: '☁️', label: 'Cansada' },
  { emoji: '💝', label: 'Amada' },
];

const Hoy: React.FC = () => {
  const { state, updateToday } = useJournal();
  const { today } = state;
  const [newTask, setNewTask] = useState('');

  const handlePriorityChange = (index: number, value: string) => {
    const newPriorities = [...today.priorities];
    newPriorities[index] = value;
    updateToday({ priorities: newPriorities });
  };

  const addTask = () => {
    if (!newTask.trim()) return;
    const task = { id: Date.now().toString(), text: newTask, completed: false };
    updateToday({ tasks: [...today.tasks, task] });
    setNewTask('');
  };

  const toggleTask = (id: string) => {
    updateToday({
      tasks: today.tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t)
    });
  };

  const handleGratitudeChange = (index: number, value: string) => {
    const newGratitude = [...today.gratitude];
    newGratitude[index] = value;
    updateToday({ gratitude: newGratitude });
  };

  return (
    <div className="space-y-8 max-w-2xl mx-auto pb-10">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-4xl font-serif text-soft-text font-light italic leading-tight">Hola, Abigail</h2>
          <p className="text-deep-rose font-medium text-sm tracking-wide mt-1">
            {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
          </p>
        </div>
        <div className="flex gap-2 bg-white/40 backdrop-blur-sm p-1.5 rounded-[1.5rem] border border-rose-pastel">
          {MOODS.map((m) => (
            <button
              key={m.label}
              onClick={() => updateToday({ mood: m.emoji })}
              className={`text-2xl p-2.5 rounded-2xl transition-all duration-300 ${today.mood === m.emoji ? 'bg-white shadow-sm scale-110' : 'hover:bg-white/40 opacity-50 hover:opacity-100'}`}
              title={m.label}
            >
              {m.emoji}
            </button>
          ))}
        </div>
      </header>

      {/* Prioridades */}
      <motion.section 
        whileHover={{ y: -2 }}
        className="bg-white p-8 rounded-[2rem] journal-shadow border border-rose-pastel/50 relative overflow-hidden"
      >
        <div className="absolute top-0 right-0 p-4 opacity-5">
          <Sparkles size={100} />
        </div>
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-sm uppercase tracking-widest">
          <Sparkles size={16} />
          <h3>Prioridades</h3>
        </div>
        <div className="space-y-4">
          {today.priorities.map((p, i) => (
            <div key={i} className="flex items-center gap-4 bg-rose-pastel/10 p-1 rounded-xl">
              <span className="text-accent-pink font-serif italic text-lg w-6">{i + 1}.</span>
              <input
                type="text"
                value={p}
                onChange={(e) => handlePriorityChange(i, e.target.value)}
                placeholder="En qué me enfocaré..."
                className="flex-1 bg-transparent border-none outline-none py-2 text-soft-text placeholder:text-soft-text/30"
              />
            </div>
          ))}
        </div>
      </motion.section>

      {/* Tareas */}
      <section className="bg-white p-8 rounded-[2.5rem] journal-shadow border border-rose-pastel/50">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-sm uppercase tracking-widest">
          <CheckCircle2 size={16} />
          <h3>Cosas por hacer</h3>
        </div>
        <div className="space-y-4 mb-8">
          {today.tasks.map((task) => (
            <motion.div 
              layout
              key={task.id} 
              className="flex items-center gap-4 group cursor-pointer"
              onClick={() => toggleTask(task.id)}
            >
              <div className={`text-accent-pink transition-all duration-300 ${task.completed ? 'scale-90' : 'group-hover:scale-110'}`}>
                {task.completed ? <CheckCircle2 size={24} fill="#fbcfe8" className="text-white" /> : <Circle size={24} className="opacity-40" />}
              </div>
              <span className={`flex-1 transition-all duration-300 ${task.completed ? 'line-through text-soft-text/30 translate-x-1' : 'text-soft-text'}`}>
                {task.text}
              </span>
            </motion.div>
          ))}
        </div>
        <div className="flex gap-3 bg-lavender-pastel/20 p-2 rounded-2xl border border-rose-pastel/30">
          <input
            type="text"
            value={newTask}
            onChange={(e) => setNewTask(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addTask()}
            placeholder="Añade una tarea con amor..."
            className="flex-1 bg-transparent border-none px-4 py-2 outline-none text-soft-text placeholder:italic"
          />
          <button 
            onClick={addTask}
            className="bg-accent-pink text-white p-3 rounded-xl hover:bg-deep-rose transition-all shadow-md shadow-accent-pink/20"
          >
            <Plus size={20} />
          </button>
        </div>
      </section>

      {/* Recordatorios y Notas rápidas */}
      <div className="grid md:grid-cols-2 gap-6">
        <section className="bg-white p-6 rounded-[2rem] journal-shadow border border-rose-pastel/50">
          <div className="flex items-center gap-2 mb-4 text-deep-rose font-bold text-xs uppercase tracking-widest">
            <Lightbulb size={14} />
            <h3>Recordar</h3>
          </div>
          <textarea
            value={today.reminders}
            onChange={(e) => updateToday({ reminders: e.target.value })}
            className="w-full h-24 bg-rose-pastel/10 rounded-xl p-3 border-none outline-none resize-none text-soft-text text-sm italic"
          />
        </section>
        <section className="bg-white p-6 rounded-[2rem] journal-shadow border border-rose-pastel/50">
          <div className="flex items-center gap-2 mb-4 text-deep-rose font-bold text-xs uppercase tracking-widest">
            <NotepadText size={14} />
            <h3>Ideas</h3>
          </div>
          <textarea
            value={today.quickNotes}
            onChange={(e) => updateToday({ quickNotes: e.target.value })}
            className="w-full h-24 bg-rose-pastel/10 rounded-xl p-3 border-none outline-none resize-none text-soft-text text-sm italic"
          />
        </section>
      </div>

      {/* Agradecimientos */}
      <section className="bg-gradient-to-br from-rose-pastel/60 to-lavender-pastel/60 p-8 rounded-[2.5rem] border border-white journal-shadow">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-sm uppercase tracking-widest">
          <Heart size={16} fill="#fbcfe8" className="text-accent-pink" />
          <h3>Hoy agradezco por...</h3>
        </div>
        <div className="space-y-4">
          {today.gratitude.map((g, i) => (
            <input
              key={i}
              type="text"
              value={g}
              onChange={(e) => handleGratitudeChange(i, e.target.value)}
              placeholder="Momentos mágicos de hoy..."
              className="w-full bg-white/40 backdrop-blur-sm border-none rounded-xl px-4 py-3 outline-none focus:bg-white transition-all text-soft-text italic"
            />
          ))}
        </div>
      </section>
    </div>
  );
};

export default Hoy;
